45→export function buildPreviewScene(project, options = {}) {
46→  const floors = getOrderedFloors(project);
47→  const activeFloorId = getDefaultActiveFloorId(project, options.activeFloorId);
48→  const activeFloor = floors.find((floor) => floor.id === activeFloorId) || null;
49→  const stackBounds = getFloorStackBounds(floors);
50→  const resolvedVisibleFloorIds = options.visibleFloorIds || floors.map((floor) => floor.id);
51→  const visibleFloorIds = new Set(resolvedVisibleFloorIds);
52→
53→  const floorDescriptors = floors.map((floor) => {
54→    const objects = buildFloorPreviewObjects(floor);
55→    return {
56→      floorId: floor.id,
57→      name: floor.name,
58→      elevation: getFloorElevation(floor),
59→      visible: visibleFloorIds.has(floor.id),
60→      objects,
61→      bounds: boundsFromObjects(objects),
62→    };
63→  });
64→
65→  const visibleObjects = floorDescriptors
66→    .filter((floor) => floor.visible)
67→    .flatMap((floor) => floor.objects);
68→  const bounds = boundsFromObjects(visibleObjects) || createFallbackBounds(stackBounds, activeFloor);
69→  const floorsWithNavigationTargets = floorDescriptors.map((floor) => ({
70→    ...floor,
71→    navigationTarget: createNavigationTarget(floor.bounds, bounds),
72→  }));
73→
74→  return {
75→    activeFloorId,
76→    visibleFloorIds: [...visibleFloorIds],
77→    floors: floorsWithNavigationTargets,
78→    bounds,
79→    defaultTarget: {
80→      x: (bounds.minX + bounds.maxX) / 2,
81→      y: (bounds.minElevation + bounds.maxElevation) / 2,
82→      z: (bounds.minY + bounds.maxY) / 2,
83→    },
84→    groundLevel: stackBounds.minElevation,
85→    hasVisibleObjects: visibleObjects.length > 0,
86→  };
87→}
