141→    animationFrame = window.requestAnimationFrame(renderFrame);
142→  };
143→
144→  const resize = () => {
145→    const width = container.clientWidth || 1;
146→    const height = container.clientHeight || 1;
147→    camera.aspect = width / height;
148→    camera.updateProjectionMatrix();
149→    renderer.setSize(width, height, false);
150→  };
151→
152→  const resolvePickTarget = (object) => {
153→    let current = object;
154→    while (current) {
155→      if (current.userData?.previewTarget) {
156→        return current.userData.previewTarget;
157→      }
158→      current = current.parent;
159→    }
160→    return null;
161→  };
162→
163→  const pickObjectAt = (clientX, clientY) => {
164→    if (navigationMode !== 'inspect') return;
165→    if (!worldRoot || !pickHandler) return;
