283→      }
284→      inspectNavigation.resetView();
285→    },
286→    fit() {
287→      inspectNavigation.resetView();
288→    },
289→    setProjectionPreset(presetName) {
290→      inspectNavigation.setProjectionPreset(presetName);
291→    },
292→    setPickHandler(handler) {
293→      pickHandler = typeof handler === 'function' ? handler : null;
294→    },
295→    setPickContext(nextContext = {}) {
296→      pickContext = {
297→        ...pickContext,
298→        ...nextContext,
299→      };
300→    },
301→    setNavigationMode,
302→    setActiveFloorContext(nextContext = {}) {
303→      const previousFloorId = activeFloorContext.floorId;
304→      const nextFloorId = nextContext.floorId ?? activeFloorContext.floorId;
305→      const floorChanged = previousFloorId !== nextFloorId;
306→
307→      if (navigationMode === 'walk' && floorChanged && previousFloorId) {
308→        saveCurrentWalkPose();
309→      }
310→
311→      activeFloorContext = {
312→        ...activeFloorContext,
313→        ...nextContext,
314→      };
315→
316→      if (navigationMode === 'walk' && (floorChanged || !walkNavigation.isLocked())) {
317→        restoreWalkPose();
318→      }
319→    },
320→    setWalkUiHandler(handler) {
321→      walkUiHandler = typeof handler === 'function' ? handler : null;
322→      emitWalkUiState();
323→    },
324→    setWalkExitHandler(handler) {
325→      walkExitHandler = typeof handler === 'function' ? handler : null;
326→    },
327→    resize,
328→    dispose() {
329→      window.cancelAnimationFrame(animationFrame);
330→      inspectNavigation.dispose();
331→      walkNavigation.dispose();
332→      renderer.domElement.removeEventListener('pointerdown', handlePointerDown);
333→      renderer.domElement.removeEventListener('pointerup', handlePointerUp);
334→      renderer.domElement.removeEventListener('pointercancel', handlePointerCancel);
335→      renderer.domElement.removeEventListener('pointerleave', handlePointerCancel);
336→
337→      if (worldRoot) {
338→        scene.remove(worldRoot);
339→        disposeScene(worldRoot, { disposeMaterials: true });
340→      }
341→
342→      if (gridHelper) {
343→        scene.remove(gridHelper);
344→        gridHelper.geometry?.dispose?.();
345→        gridHelper.material?.dispose?.();
346→      }
347→
348→      disposeMaterialPalette(materialPalette);
349→      renderer.dispose();
350→      renderer.domElement.remove();
351→    },
352→    materialPalette,
353→  };
354→}
